SELECT qSoloVendItem.[Model Item No_] AS Article, qSoloVendItem.[Variable Code 01], qSoloVendItem.Salesperson, qSoloVendItem.[Delete Reason], qSoloVendItem.[Assortment Code], Sum(qSoloVendItem.QuantitySold) AS QuantitySold, Sum(qSoloVendItem.PairsSold) AS PairsSold, qSoloVendItem.[Order Date], qSoloVendItem.[Salesperson Code], qSoloVendItem.ColorCode, qSoloVendItem.[Sell-to Customer No_] AS CustomerCode, Sum(qSoloVendItem.SalesValue) AS salesvalue, Customer.[Geographical Zone], Customer.Name AS CustomerName, Customer.[Blocked For Assignement], qSoloVendItem.OrderPeriod, Sum(qSoloVendItem.PairsShipped) AS PairsShipped, Sum(qSoloVendItem.ShippedQuantity) AS ShippedQuantity, Sum(qSoloVendItem.ValueShipped) AS ValueShipped, Customer.[Geographical Zone 2], qSoloVendItem.TipoOrdine AS OrderType, Sum(qSoloVendItem.ReturnedValue) AS ReturnedValue, Sum(qSoloVendItem.ReturnedQuantity) AS ReturnedQuantity, Sum(qSoloVendItem.ReturnedPairs) AS ReturnedPairs, qSoloVendItem.ReturnReasonCode, qSoloVendItem.DocumentType, qSoloVendItem.ClienteSpedizione, qSoloVendItem.ClienteSpedizione2, qSoloVendItem.IndirizzoSpedizione, qSoloVendItem.IndirizzoSpedizione2, qSoloVendItem.CittaSpedizione, qSoloVendItem.CodicePostaleSpedizione, qSoloVendItem.CountySpedizione, qSoloVendItem.[Requested Delivery Date], Sum(qSoloVendItem.PairsReadyForShipping) AS PairsReadyForShipping, Sum(qSoloVendItem.QuantityReadyForShipping) AS QuantityReadyForShipping, Sum(qSoloVendItem.ValueReadyForShipping) AS ValueReadyForShipping, qSoloVendItem.Taglia, qSoloVendItem.OrdinamentoTaglia, qSoloVendItem.[Payment Terms Code], qSoloVendItem.[Payment Method Code], Sum(qSoloVendItem.InvoicedQuantity) AS InvoicedQuantity, Sum(qSoloVendItem.PairsInvoiced) AS PairsInvoiced, Sum(qSoloVendItem.ValueInvoiced) AS ValueInvoiced, qSoloVendItem.CalcoloScontoFattura, qSoloVendItem.ScontoFattura, Customer.[E-Mail]
FROM qSoloVendItem INNER JOIN Customer ON qSoloVendItem.[Sell-to Customer No_] = Customer.No_
GROUP BY qSoloVendItem.[Model Item No_], qSoloVendItem.[Variable Code 01], qSoloVendItem.Salesperson, qSoloVendItem.[Delete Reason], qSoloVendItem.[Assortment Code], qSoloVendItem.[Order Date], qSoloVendItem.[Salesperson Code], qSoloVendItem.ColorCode, qSoloVendItem.[Sell-to Customer No_], Customer.[Geographical Zone], Customer.Name, Customer.[Blocked For Assignement], qSoloVendItem.OrderPeriod, Customer.[Geographical Zone 2], qSoloVendItem.TipoOrdine, qSoloVendItem.ReturnReasonCode, qSoloVendItem.DocumentType, qSoloVendItem.ClienteSpedizione, qSoloVendItem.ClienteSpedizione2, qSoloVendItem.IndirizzoSpedizione, qSoloVendItem.IndirizzoSpedizione2, qSoloVendItem.CittaSpedizione, qSoloVendItem.CodicePostaleSpedizione, qSoloVendItem.CountySpedizione, qSoloVendItem.[Requested Delivery Date], qSoloVendItem.Taglia, qSoloVendItem.OrdinamentoTaglia, qSoloVendItem.[Payment Terms Code], qSoloVendItem.[Payment Method Code], qSoloVendItem.CalcoloScontoFattura, qSoloVendItem.ScontoFattura, Customer.[E-Mail];

